sql:
SELECT COUNT(*) AS pending_payment_count
FROM fee_payments
WHERE payment_status = 'pending';

SELECT remark_id, fee_id, remark_text
FROM fee_remarks
WHERE remark_date = '2023-01-02';

SELECT description, amount
FROM fees
WHERE fee_id = 1;

SELECT DISTINCT d.dept_name
FROM departments d
INNER JOIN fees f ON d.dept_id = f.dept_id;

SELECT COUNT(remark_id) AS total_remarks
FROM fee_remarks
WHERE fee_id = 1;

